import { jsPDF } from 'jspdf';

export const apcoFooterBase64 = "data:image/png;base64,";

/**
 * Draws the APCO family branding footer centered horizontally at the bottom of the page.
 */
export function drawBrandingFooter(doc: jsPDF, pageWidth: number, contentWidth: number): void {
  const footerWidth = contentWidth;
  // Original image width: 1024, height: 576 (16:9 aspect ratio)
  const originalWidth = 1024;
  const originalHeight = 576;
  const scaleFactor = footerWidth / originalWidth;
  const footerHeight = originalHeight * scaleFactor * 0.7; // 30% height reduction
  const footerX = (pageWidth - footerWidth) / 2;
  const bottomMargin = 7; // safe bottom margin in mm
  const footerY = doc.internal.pageSize.getHeight() - footerHeight - bottomMargin;
  try {
    doc.addImage(apcoFooterBase64, 'PNG', footerX, footerY, footerWidth, footerHeight, undefined, 'FAST');
  } catch (err) {
    console.error('Failed to draw footer branding banner:', err);
  }
}

/**
 * Applies the APCO branding footer across all pages of a jsPDF document.
 */
export function applyBrandingFooterToDoc(doc: jsPDF, pageWidth: number, contentWidth: number): void {
  const pageCount = doc.getNumberOfPages();
  for (let i = 1; i <= pageCount; i++) {
    doc.setPage(i);
    drawBrandingFooter(doc, pageWidth, contentWidth);
  }
}
